using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class PartsTraining : TrainingContentBase
{
    public PartsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Overview",
            Slug = "parts-overview",
            Summary = "What parts are, the three classification axes (procurement, inventory class, item kind), statuses, BOMs, vendor sources, routing, and how parts connect to jobs, inventory, purchasing, and sales.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","inventory","catalog","sourcing"]""",
            ContentJson = """{"body":"## Parts Catalog Overview\n\nThe Parts Catalog is the central register for every item your shop manufactures, purchases, or stocks. Each part record captures the full engineering definition — what the part is, how it's sourced, where it lives in inventory, and how it's built. Parts connect to nearly every other module: jobs consume parts, inventory tracks their quantities, purchase orders procure them, sales orders sell them, and operations define how to produce them.\n\n### What Is a Part?\n\nA part is any discrete item your business tracks — finished goods, raw materials, sub-assemblies, components, consumables, fasteners, electronics, packaging, and tooling. Every part gets a system-generated part number and a name. New parts start in Draft status and progress through Prototype → Active → Obsolete.\n\n### The Three Classification Axes\n\nA part isn't defined by a single \"type\" — that one field used to overload three distinct concepts. Each part is now classified by **three orthogonal axes**, chosen on the New Part screen:\n\n1. **Procurement Source** — how the part is sourced.\n   - **Make** — produced in-house. May still send out individual operations (subcontract ops).\n   - **Buy** — purchased complete from a vendor.\n   - **Subcontract** — entire part outsourced; the vendor builds it, we never touch it.\n   - **Phantom** — a logical assembly that never physically exists; explodes through to its children for MRP.\n2. **Inventory Class** — which bucket the part lives in.\n   - **Raw**, **Component**, **Subassembly**, **FinishedGood**, **Consumable**, **Tool**.\n3. **Item Kind** — descriptive taxonomy (admin-configurable) such as Fastener, Electronic, Packaging, Hardware, Material.\n\nNot every combination is meaningful — eleven viable (procurement × inventory class) combinations are documented and drive which detail tabs appear, which workflow runs on creation, and which gates fire at promotion time. The detail page's tab layout adapts to the axes automatically.\n\n**Identity axes are immutable after a part is created.** Procurement Source and Inventory Class drive everything downstream — which tabs render, which validators run, which cost calculations are valid. Changing them mid-life would invalidate history. Use a dedicated migration tool if a part truly needs to be reclassified.\n\n### Tier 0 Identity Fields\n\nBeyond the three axes, every part record carries:\n\n- **Traceability** — None (bulk), Lot (by batch), or Serial (per unit). Replaces the old isSerialTracked boolean.\n- **ABC Class** — A/B/C for value-based prioritization (cycle counting frequency, control intensity).\n- **Manufacturer** + **Manufacturer Part Number** — the OEM identity (distinct from a distributor's vendor part number).\n- **Revision** — engineering rev. Defaults to A.\n- **Description** — long-form notes.\n\n### Status Lifecycle\n\nFour statuses gate what the part can do:\n\n- **Draft** — record exists; not visible to production workflows or purchasing.\n- **Prototype** — usable in jobs and inventory but flagged as not finalized.\n- **Active** — fully approved for production, purchasing, and sales. Default for parts that survived their workflow.\n- **Obsolete** — preserved for historical traceability. Won't appear in new orders.\n\nParts are never hard-deleted. Status changes happen via the Identity cluster's Status field on the detail page.\n\n### The Detail Page\n\nThe Part detail page is a multi-tab cluster system. Tabs are not fixed — they're resolved per (procurement, inventory class) combination by the layout resolver. Common tabs:\n\n- **Identity** — always first. Part number, axes (read-only), name, revision, description, status. Edit name/description/revision/status inline; axes are immutable.\n- **Inventory** — min stock, reorder point, reorder quantity, safety stock, traceability, ABC class. Hidden for non-stocked combinations.\n- **MRP** — planning policy: lot sizing rule, fixed/min order qty, multiples, planning + demand fences. Hidden when the part isn't MRP-planned.\n- **Cost** — manual cost override, current cost calculation snapshot id, valuation class, landed-cost breakdown. Hidden for Phantom combos.\n- **Pricing** — list prices, effective dates, history.\n- **Material** — material spec, weight/dimensions/volume (canonical SI columns + display unit so the user types in their preferred unit).\n- **UoM** — stock / purchase / sales units of measure. Lookup-driven dropdowns.\n- **Quality** — receiving inspection toggle, template, frequency, skip-after-N count.\n- **Routing** — manufacturing operations (Make and Phantom combos).\n- **BOM** — bill of materials (Make / Subassembly / Phantom). Table or tree view.\n- **Sources** — vendor sources (Buy / Subcontract / dual-sourced parts). One row per (vendor, part) intersection.\n- **Alternates** — substitute parts.\n- **Purchase History** — most recent POs that included this part.\n- **3D Viewer** — appears only when an STL file is attached.\n- **Activity** — chronological log of every definitional change.\n- **Files** — always last. CAD, drawings, datasheets.\n\nEach editable cluster has its own Save / Cancel pair (lower-right of the cluster). You can edit Identity without touching Inventory; saves are scoped per cluster. The page never has a single global Save.\n\n### Vendor Sources (Sources Tab)\n\nFor parts that are bought (or that have Buy options on a Make-axis part), the **Sources** tab lists the (Vendor, Part) intersections — one row per vendor that supplies this part. Each source captures vendor-scoped sourcing data:\n\n- Vendor's part number\n- Vendor's manufacturer part number (distributor case)\n- Per-vendor lead time, MOQ, pack size\n- Country of origin, HTS code\n- AVL approval flag, certifications, last-quoted date\n- **Preferred** flag — at most one preferred vendor per part. Mirrors to the Part's PreferredVendorId.\n- **Tiered pricing** — quantity breaks (min qty ≤ requested qty wins), with effective-from and effective-to dates.\n\nAdding a source is a normal create; the price tier list is managed inline. Setting a new preferred source automatically un-preferreds the previous one.\n\n### Bill of Materials (BOM)\n\nFor Make and Phantom assemblies, the BOM tab lists every component:\n\n- **Child Part** — entity-picker search. Cannot be the parent itself.\n- **Quantity** — per parent unit.\n- **Source Type** — Make (manufactured in-house, may trigger sub-job), Buy (purchased), Stock (pulled from inventory).\n- **Reference Designator** — engineering reference (R1, C4, J2 for electronics).\n- **Lead Time Days** — days to obtain this specific component.\n- **Notes** — free-form.\n\nBOM entries can be viewed as a flat sortable table or a hierarchical tree. The **Used In** view (reverse BOM) is reachable via the Alternates / Sources cross-reference and shows parent assemblies that consume this part.\n\n### Routing (Operations)\n\nMake-axis parts have a Routing tab listing manufacturing operations in sequence:\n\n- **Step Number**, **Title**, **Instructions**, **Work Center**, **Estimated Minutes**, **QC Checkpoint** (with QC Criteria), and **Referenced Operation** (cross-reference for dependencies).\n- Each operation can subcontract one step (an op-level IsSubcontract flag) — distinct from a wholly-subcontracted part.\n- BOM entries can be assigned to operations as **Operation Materials** so the routing knows which materials are consumed at each step.\n- Operations support per-operation file attachments and an activity log.\n\nThe routing renders in list mode (sequential cards) or flow mode (visual diagram).\n\n### How Parts Connect to Other Modules\n\n**Jobs** — when a job is created on the Kanban board, it can be linked to a part. The part's BOM drives material requirements, the routing defines the production steps.\n\n**Inventory** — parts are tracked in storage locations and bins. The Inventory cluster surfaces total quantity on hand and a low-stock warning when quantity drops below the min stock threshold.\n\n**Purchase Orders** — when a BOM entry has source type Buy, the system knows the component needs procurement. The preferred vendor (from the Sources tab) drives PO creation.\n\n**Sales Orders & Quotes** — parts appear as line items with pricing from the part's price history (or vendor tier price for cost-plus margin).\n\n**Assets** — Tool-class parts can be linked to a tooling asset for shot count tracking and maintenance scheduling.\n\n**Barcode/QR** — every part can have a barcode label printed. Scanning a part's barcode on the Parts page populates the search field instantly.\n\n### Creating a Part\n\nNew Part starts with a 4-question fork dialog that selects the axes (procurement, inventory class, plus a question or two about traceability and inspection). Based on the answers, the system picks a workflow definition and routes you into a guided multi-step form (Basics → Inventory → Quality → Sourcing → Costing → … → Save). You can pause at any step; the partial state is preserved as a draft and shown as a ghost row on the parts list, resumable from where you left off.\n\nLightweight cases (Raw Material, Consumable) drop straight into a single-page express form instead of a multi-step workflow.\n\n### View Modes\n\nThe parts list page has two view modes: **Table View** (sortable, column-managed data table) and **Card Grid View** (visual cards). Toggle in the upper-right; preference is saved per user.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog — Guided Tour",
            Slug = "parts-walkthrough",
            Summary = "A guided tour of the parts list, axis filters, view toggle, the New Part fork, and a glance at the resolver-driven detail page (Identity / Inventory / Cost / Sources / BOM / Routing / Activity / Files).",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","walkthrough","sourcing"]""",
            ContentJson = """{"appRoute":"/parts","startButtonLabel":"Tour Parts Catalog","steps":[{"element":"[data-testid='new-part-btn']","popover":{"title":"New Part","description":"Click here to start a new part. You'll first answer a short fork: how the part is procured (Make, Buy, Subcontract, Phantom), which inventory bucket it belongs to (Raw, Component, Subassembly, FinishedGood, Consumable, Tool), and a couple of questions about traceability and inspection. Based on your answers, the system picks a workflow and walks you through the right cluster of fields.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Parts","description":"Search by part number, name, manufacturer, or external part number. Press Enter to apply. Barcode scanners feed into this field automatically — scan a label and the matching part is found.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(1)","popover":{"title":"Status Filter","description":"Filter by lifecycle status: Draft (work-in-progress), Prototype (in testing), Active (approved for use), or Obsolete (preserved for history but not for new orders). Pick 'All' to see everything.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(2)","popover":{"title":"Procurement Source Filter","description":"Filter by procurement axis: Make (in-house), Buy (purchased), Subcontract (vendor builds it whole), or Phantom (logical assembly that never physically exists). Combine with the Inventory Class filter to narrow further.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(3)","popover":{"title":"Inventory Class Filter","description":"Filter by inventory bucket: Raw, Component, Subassembly, FinishedGood, Consumable, or Tool. This axis decides which inventory rules apply (stocking, traceability, ABC class).","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Mode Toggle","description":"Switch between Table View (sortable data table with column management) and Card Grid View (visual cards). Your preference is saved across sessions.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Parts Data Table","description":"Click any row to open the part detail panel. Columns include Part #, Name, Procurement, Class, Status, BOM count, Effective Price, and a Completeness chip. Click headers to sort. Use the gear icon to show/hide columns or rearrange them. Draft rows from in-progress workflow runs appear as 'ghost' rows pinned to the top — click to resume, or click the X to abandon the draft.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Field Reference",
            Slug = "parts-field-reference",
            Summary = "Complete reference for every field, axis, status, validation rule, table column, and detail-page cluster in the Parts Catalog.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","reference","sourcing"]""",
            ContentJson = """{"title":"Parts Catalog Field Reference","groups":[{"heading":"Identity Axes (chosen on the New Part fork)","items":[{"label":"Procurement Source (required)","value":"Make / Buy / Subcontract / Phantom. Determines workflow path on creation, which detail-page tabs render, and which gates fire at promotion. Immutable after creation. data-testid: part-procurement-source"},{"label":"Inventory Class (required)","value":"Raw / Component / Subassembly / FinishedGood / Consumable / Tool. Determines which inventory rules apply (stocking, traceability, ABC). Immutable after creation. data-testid: part-inventory-class"},{"label":"Item Kind (optional)","value":"Admin-configurable taxonomy from reference_data group 'part.item_kind' (Fastener, Electronic, Packaging, Hardware, Material, etc.). Descriptive only — does not gate any logic."}]},{"heading":"Identity Cluster Fields","items":[{"label":"Part Number","value":"System-generated on creation. Read-only. Format = categorical prefix (PRT, ASM, RAW, CON, TLG, FST, ELC, PKG) + 5-digit zero-padded sequence. Cannot be changed."},{"label":"Name (required)","value":"Short canonical identifier (e.g., 'Sheath Mudkipper'). Max 256 characters. data-testid: part-identity-name / part-name"},{"label":"Description","value":"Long-form notes. Optional. Max 2000 characters. data-testid: part-identity-description / part-description"},{"label":"Revision","value":"Engineering rev letter. Default 'A'. Max 5 characters. Increment on design change (A → B → C). data-testid: part-identity-revision / part-revision"},{"label":"Status (required)","value":"Draft / Prototype / Active / Obsolete. Edit inline via the Identity cluster's Status select. data-testid: part-identity-status"}]},{"heading":"Tier 0 Identity Fields","items":[{"label":"Traceability","value":"None (bulk, no tracking) / Lot (by batch) / Serial (per unit). Required. Replaces the old isSerialTracked boolean."},{"label":"ABC Class","value":"A (high value, tight control) / B (moderate) / C (low value, loose control) / Unset. Drives cycle-count frequency and control rigor."},{"label":"Manufacturer","value":"OEM company name. Optional. Distinct from a distributor's vendor name."},{"label":"Manufacturer Part Number","value":"OEM's part number. Optional. Distinct from a distributor's vendor part number — both can coexist on a VendorPart row."}]},{"heading":"Inventory Cluster Fields","items":[{"label":"Min Stock","value":"Minimum quantity to keep on hand. When inventory drops below this, a low-stock warning appears. Optional. Must be >= 0."},{"label":"Reorder Point","value":"Quantity level at which a reorder should be triggered. Used by MRP. Optional. Must be >= 0."},{"label":"Reorder Quantity","value":"How many units to order when reordering. Optional."},{"label":"Safety Stock (days)","value":"Buffer days of stock to maintain beyond the calculated reorder point. Optional."},{"label":"Traceability","value":"None / Lot / Serial. See Tier 0 Identity."},{"label":"ABC Class","value":"A / B / C / Unset. See Tier 0 Identity."}]},{"heading":"Cost Cluster Fields","items":[{"label":"Manual Cost Override","value":"Currency input. When set, overrides the calculated landed cost. Currency-formatted with the company default currency. Clear via the input's clear button (negative or empty saves null)."},{"label":"Cost Calculation Id","value":"Read-only. The current cost-calculation snapshot id. Background job recomputes on BOM / vendor / price changes."},{"label":"Valuation Class","value":"Read-only label. Pillar 2 valuation grouping (admin-configurable in reference_data)."},{"label":"Landed Cost Surface","value":"Read-only breakdown of unit cost + freight + duty + tariffs. Sourced from VendorPartPriceTier and shipment cost allocation."}]},{"heading":"Sources Tab (VendorPart Intersection)","items":[{"label":"Add Vendor Source","value":"Open dialog to add a (Vendor, Part) row. Required: Vendor (entity picker)."},{"label":"Vendor Part Number","value":"Vendor's catalog number for this part."},{"label":"Vendor MPN","value":"Vendor's manufacturer part number — for the case where the vendor is a distributor and the part has a different OEM identity."},{"label":"Lead Time (days)","value":"Per-vendor lead time. Overrides the part-level default for this source."},{"label":"MOQ","value":"Minimum order quantity for this vendor."},{"label":"Pack Size","value":"Vendor packs in multiples of this number."},{"label":"Country of Origin","value":"For HTS/customs purposes."},{"label":"HTS Code","value":"Harmonized Tariff Schedule code. Used by import duty calculations."},{"label":"AVL Approved","value":"Toggle. Whether this source is on the Approved Vendor List."},{"label":"Certifications","value":"Free-text. Quality certifications (ISO 9001, AS9100, RoHS, etc.)."},{"label":"Last Quoted At","value":"Date the vendor last quoted on this part. Stale-source detection."},{"label":"Preferred","value":"Toggle. At most one preferred source per part — flipping this on auto-flips off the previous preferred. Mirrors to Part.PreferredVendorId."},{"label":"Price Tiers","value":"Quantity-break rows: min qty + unit price + currency + effective-from + effective-to. Inline add / edit / remove."}]},{"heading":"BOM Cluster (Make / Subassembly / Phantom)","items":[{"label":"Child Part (required)","value":"Entity picker searching parts. Cannot be the parent itself."},{"label":"Quantity (required)","value":"How many child parts per parent unit. Must be > 0. Default 1."},{"label":"Source Type","value":"Make (in-house, may trigger sub-job) / Buy (purchased) / Stock (from inventory). Default Buy."},{"label":"Reference Designator","value":"Engineering reference (R1, C4, J2)."},{"label":"Lead Time Days","value":"Days to obtain this specific component. Displayed as 'Xd' in the BOM table."},{"label":"Notes","value":"Free-form."}]},{"heading":"Routing Cluster (Make Only)","items":[{"label":"Step Number","value":"Sequence (1, 2, 3...). Auto-populated for new ops with the next available number."},{"label":"Title (required)","value":"Short op name (e.g., 'CNC Rough Cut', 'Deburr', 'Heat Treat'). Max 200 characters."},{"label":"Instructions","value":"Detailed multi-line work instructions for the operator."},{"label":"Work Center","value":"Entity picker (work centers). Optional."},{"label":"Estimated Minutes","value":"Expected duration. Optional. Must be >= 1 if provided."},{"label":"Is Subcontract (toggle)","value":"When ON, this single operation is sent out to a subcontracter. Distinct from procurementSource = Subcontract on the part level (which means the entire part is outsourced)."},{"label":"QC Checkpoint (toggle)","value":"When ON, requires inspection before next step proceeds."},{"label":"QC Criteria","value":"Textarea, shown when QC Checkpoint is on."},{"label":"Operation Materials","value":"BOM entries assigned to this op. Each row = (BOM entry, quantity consumed at this step)."}]},{"heading":"Quality Cluster","items":[{"label":"Requires Receiving Inspection (toggle)","value":"When ON, every receipt of this part triggers a QC inspection."},{"label":"Receiving Inspection Template","value":"FK to QcTemplate. Determines the inspection checklist."},{"label":"Inspection Frequency","value":"Always / Sample / Skip-after-N. Drives the inspection skip logic."},{"label":"Inspection Skip After N","value":"After N successful inspections in a row, subsequent receipts skip inspection until a defect is found."}]},{"heading":"Material Cluster","items":[{"label":"Material Spec","value":"FK to material specification (reference_data group 'material.spec'). 6061-T6 Aluminum, 304 Stainless, ABS Plastic, etc."},{"label":"Weight (canonical g) + Display Unit","value":"Weight stored in grams. Display unit is what the user typed (g, kg, oz, lb). Round-trip preserves the entry unit."},{"label":"Length / Width / Height (canonical mm) + Display Unit","value":"Dimensions in mm. Display unit (mm, cm, m, in, ft) preserved."},{"label":"Volume (canonical mL) + Display Unit","value":"Volume in milliliters. Display unit (mL, L, oz, gal) preserved."},{"label":"Valuation Class","value":"FK to reference_data group 'valuation.class'. Pillar 2 inventory valuation grouping."}]},{"heading":"UoM Cluster","items":[{"label":"Stock UoM","value":"Unit the part is stocked in (the canonical inventory unit). FK to reference_data."},{"label":"Purchase UoM","value":"Unit the part is purchased in. May differ from stock UoM (e.g., stock by piece, purchase by case)."},{"label":"Sales UoM","value":"Unit the part is sold in."}]},{"heading":"MRP Cluster","items":[{"label":"Is MRP Planned (toggle)","value":"Whether MRP includes this part in its planning runs."},{"label":"Lot Sizing Rule","value":"FixedOrderQty / LotForLot / EconomicOrderQty / FixedPeriod. Drives how MRP groups demand into orders."},{"label":"Fixed Order Quantity","value":"For FixedOrderQty rule. Always order this much."},{"label":"Minimum Order Quantity","value":"Floor for any single order."},{"label":"Order Multiple","value":"Order in multiples of this number."},{"label":"Planning Fence (days)","value":"Inside this fence, MRP doesn't auto-generate new orders — manual control only."},{"label":"Demand Fence (days)","value":"Inside this fence, demand changes are not allowed without override."}]},{"heading":"Pricing Cluster","items":[{"label":"Set New Price","value":"Currency input. Saving creates a new price row and marks the previous as historical."},{"label":"Effective From","value":"Date the new price takes effect. Defaults to today."},{"label":"Notes","value":"Optional. Reason for the price change."},{"label":"Price History","value":"Past prices: price, effective-from, effective-to (or '---' if current)."}]},{"heading":"Detail Page Tab Layout","items":[{"label":"Resolver-driven","value":"Tabs are NOT fixed — they're computed from (procurementSource, inventoryClass) by PartDetailLayoutResolverService. Identity always first, Activity → Files always last."},{"label":"Common tabs","value":"Identity, Inventory, MRP, Cost, Pricing, Material, UoM, Quality, Routing, BOM, Sources, Alternates, Purchase History, 3D Viewer, Activity, Files."},{"label":"URL sync","value":"Active tab is bound to ?tab=<id> so refresh and shared links land on the right tab."},{"label":"Per-cluster save","value":"Each editable cluster has its own Save / Cancel pair (lower-right). No global page-level Save. Saves are scoped — edit Identity without affecting Inventory."}]},{"heading":"Parts List Table Columns","items":[{"label":"Part # (partNumber)","value":"System-generated. Sortable. Bold monospace. 120px."},{"label":"Name","value":"Part name. Sortable. Flexible width. Includes a completeness badge."},{"label":"Procurement (procurementSource)","value":"Make / Buy / Subcontract / Phantom chip. Sortable."},{"label":"Class (inventoryClass)","value":"Raw / Component / Subassembly / FinishedGood / Consumable / Tool chip. Sortable."},{"label":"Status","value":"Color-coded badge: Active=green, Draft=gray, Prototype=blue, Obsolete=red. Sortable + filterable."},{"label":"BOM Count","value":"Number of direct BOM entries. Center-aligned. 60px."},{"label":"Effective Price","value":"Current list price (or '---' if no price configured)."},{"label":"Completeness","value":"Chip showing how complete the part record is (Identity → Sourcing → Pricing → Quality coverage)."}]},{"heading":"Validation Rules","items":[{"label":"Procurement Source / Inventory Class","value":"Required on creation. Cannot be changed afterward."},{"label":"Name","value":"Required. Max 256 characters."},{"label":"Description","value":"Optional. Max 2000 characters."},{"label":"Revision","value":"Optional. Max 5 characters. Defaults to 'A'."},{"label":"Traceability","value":"Required. None / Lot / Serial."},{"label":"Min Stock / Reorder Point / Safety Stock","value":"Optional. Must be >= 0."},{"label":"BOM Quantity","value":"Required. Must be > 0."},{"label":"Operation Step Number","value":"Required. Must be >= 1."},{"label":"Operation Title","value":"Required. Max 200 characters."},{"label":"VendorPart preferred uniqueness","value":"Server-side: at most one VendorPart per part with isPreferred=true. Setting it true on one row clears it on every other."},{"label":"Submit button + validation popover","value":"All forms use the <app-validation-button> stereotype: when invalid, a small warning-triangle icon appears next to a disabled Save. Click the icon to see the list of violations."}]},{"heading":"Buttons and Actions","items":[{"label":"New Part (page header)","value":"Opens the 4-question fork dialog. data-testid: new-part-btn"},{"label":"Resume Draft (parts list)","value":"Click a 'ghost' draft row (a workflow run that hasn't materialized a Part yet) to resume the workflow where you left off."},{"label":"Abandon Draft","value":"X button on a ghost draft row. Discards the in-progress run."},{"label":"Edit (cluster header)","value":"Each editable cluster has an inline Edit button. Click to enter edit mode for that cluster only."},{"label":"Save / Cancel (cluster footer)","value":"Per-cluster. Save commits this cluster's changes. Cancel reverts in-progress edits and exits edit mode."},{"label":"Status change","value":"Identity cluster Status select — Draft / Prototype / Active / Obsolete. No separate status buttons; one form field."},{"label":"Add Vendor Source (Sources tab)","value":"Opens the VendorPart create dialog."},{"label":"Add Price Tier","value":"Inline action on a vendor source — adds a quantity-break row."},{"label":"Add BOM Entry","value":"Opens the BOM entry creation dialog with entity picker for child part."},{"label":"Add Operation","value":"Opens the operation creation dialog with auto-incremented step number."},{"label":"View Mode Toggle (page level)","value":"Switch between Table View and Card Grid View."},{"label":"Row click (parts table)","value":"Opens the part detail panel."}]},{"heading":"Activity Logging","items":[{"label":"Created","value":"On part create — one ActivityLog row anchored to the part with action 'created' and a description naming the part number, name, procurement, and inventory class."},{"label":"Updated","value":"Per save (rollup rule) — one row per request, with description summarizing all changed fields."},{"label":"Deleted","value":"On soft-delete — one row anchored to the part with action 'deleted'."},{"label":"VendorPart mutations","value":"Indexing-points rule — VendorPart create / update / delete / price-tier add / price-tier remove each emit two activity rows: one anchored to the Part, one to the Vendor."}]},{"heading":"Barcode Scanner Integration","items":[{"label":"Scanner context","value":"The Parts page sets the global scanner context to 'parts'. Scans on this page populate the search filter."},{"label":"Scan behavior","value":"Scanned value is dropped into the search input and the parts list reloads with that value as the search term — finds the part by its barcode-encoded part number."},{"label":"Supported scanners","value":"USB barcode scanners (keyboard wedge mode) and NFC readers (ACR122U with NTAG215 tags). Scanner must be in keyboard emulation mode."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Knowledge Check",
            Slug = "parts-quiz",
            Summary = "Test your knowledge: the three classification axes, identity immutability, BOM source types, vendor sources, routing, traceability, and the per-cluster save model.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["parts","bom","operations","quiz","sourcing"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pt1","text":"A part is built from multiple sub-components in your shop. Which Procurement Source / Inventory Class combination fits?","options":[{"id":"a","text":"Buy / Component"},{"id":"b","text":"Make / Subassembly","isCorrect":true},{"id":"c","text":"Subcontract / FinishedGood"},{"id":"d","text":"Phantom / Raw"}],"explanation":"Make + Subassembly: 'Make' because you produce it in-house, 'Subassembly' because it's an assembly that's itself a component of something larger. The BOM tab will appear on the detail page; the Routing tab will appear because Make-axis parts have manufacturing operations."},{"id":"pt2","text":"What's the difference between a part with procurementSource = Subcontract and an operation with isSubcontract = true?","options":[{"id":"a","text":"They mean the same thing — both indicate vendor outsourcing"},{"id":"b","text":"Subcontract on the part = the entire part is built by a vendor; isSubcontract on an operation = ONE step is sent out, but the rest of the part is made in-house","isCorrect":true},{"id":"c","text":"Subcontract on the part is the legacy form; only operation-level subcontracting is supported now"},{"id":"d","text":"isSubcontract on an operation triggers an automatic PO; Subcontract on a part doesn't"}],"explanation":"They model two different scopes. Procurement Source = Subcontract means the whole part is outsourced — the vendor delivers it complete. An operation-level isSubcontract flag on a Make-axis part means one step in the routing is sent out (e.g., we machine the housing in-house but send it out for anodizing)."},{"id":"pt3","text":"Why are Procurement Source and Inventory Class immutable after a part is created?","options":[{"id":"a","text":"They aren't — there's an Edit button on the Identity cluster that lets you change them"},{"id":"b","text":"They drive which detail tabs appear, which validators run, which workflows fire on creation, and which gates fire at promotion. Changing them mid-life would invalidate every downstream reference and history record","isCorrect":true},{"id":"c","text":"It's a database constraint with no business reason"},{"id":"d","text":"Only the procurement axis is immutable; inventory class can be changed freely"}],"explanation":"Both axes are baked into every cost calculation, every BOM that uses this part, every vendor source, and the part's own activity history. Reclassifying mid-life would silently invalidate all of that. If a part truly needs to be reclassified, use a dedicated migration tool that re-runs the workflow and writes a new audit row — not an inline edit."},{"id":"pt4","text":"What does Traceability = Lot mean for a part?","options":[{"id":"a","text":"The part is tracked by individual serial numbers, one per unit"},{"id":"b","text":"The part is tracked by batch — receipts, moves, and consumption are recorded against the lot, not against individual units","isCorrect":true},{"id":"c","text":"The part can only be sold by the lot, never split"},{"id":"d","text":"The part is exempt from inventory tracking entirely"}],"explanation":"Lot traceability means the smallest tracked unit is the batch (lot). Receipts create a LotRecord; moves and consumption reference the lot id. Use Lot for materials and chemicals where individual units aren't distinguishable. Use Serial for high-value or regulated items where every unit needs its own identity. Use None for bulk consumables where neither matters."},{"id":"pt5","text":"You're editing a part. You change the Name in the Identity cluster, then click Save. What happens?","options":[{"id":"a","text":"The whole part is saved — Identity, Inventory, Cost, and every other cluster"},{"id":"b","text":"Only the Identity cluster's fields are sent to the server. Other clusters' data isn't touched","isCorrect":true},{"id":"c","text":"Nothing — there's no per-cluster save; the page has a global Save button"},{"id":"d","text":"The save fails because the Inventory cluster is also dirty"}],"explanation":"The detail page has per-cluster save / cancel pairs (lower-right of each cluster). Each Save sends only that cluster's fields. This means you can edit Identity safely without touching Inventory, and vice versa — there's no risk of accidentally saving stale values from another cluster."},{"id":"pt6","text":"You add a vendor source to a part and toggle 'Preferred' on. Another vendor source on the same part was previously preferred. What happens?","options":[{"id":"a","text":"The save is rejected — there can only be one preferred per part, you must un-prefer the other one first"},{"id":"b","text":"Both rows end up preferred — the constraint is advisory","isCorrect":false},{"id":"c","text":"The previous preferred is automatically un-preferred — the server enforces at most one preferred per part. Part.PreferredVendorId is updated to point at the new preferred row","isCorrect":true},{"id":"d","text":"Only the database constraint catches it on the next read; the save itself is silent"}],"explanation":"The preferred-uniqueness invariant is enforced server-side: setting isPreferred=true on one VendorPart row automatically unsets it on every other VendorPart for the same part within the same SaveChanges. The Part.PreferredVendorId column is a denormalized mirror that points at the preferred row for fast access — it's kept in sync as part of the same operation."},{"id":"pt7","text":"You add a price tier to a vendor source: minQuantity=100, unitPrice=$1.50, effectiveFrom=2026-04-01. The same vendor already has minQuantity=10, unitPrice=$2.00 (current). A buyer asks for 250 units. Which tier applies?","options":[{"id":"a","text":"$2.00 because that tier was created first"},{"id":"b","text":"$1.50 because the requested quantity (250) is at or above 100, and 100 is the highest minQuantity that still fits","isCorrect":true},{"id":"c","text":"$2.00 because tiers don't apply to vendor-quoted prices"},{"id":"d","text":"The system averages the tiers"}],"explanation":"Quantity-break rule: of the active tiers (effectiveFrom <= today, effectiveTo null or > today), pick the one whose minQuantity is the highest value that's still <= the requested quantity. 250 >= 100, so the $1.50 tier wins. If the buyer asked for 50 units instead, only the minQ=10 tier would qualify and $2.00 would apply."},{"id":"pt8","text":"What's the role of the BOM source type 'Make' on a BOM entry?","options":[{"id":"a","text":"It marks the entry as obsolete"},{"id":"b","text":"It tells the system the component is manufactured in-house, which can trigger a sub-job during production planning","isCorrect":true},{"id":"c","text":"It locks the BOM entry from being edited"},{"id":"d","text":"It hides the entry from the BOM tree view"}],"explanation":"Source Type = Make means the component is itself manufactured in-house. During production planning (BOM explosion), the system can create a sub-job to produce the Make component before the parent job needs it. Buy entries trigger purchase orders; Stock entries assume the component is on hand."},{"id":"pt9","text":"Which tabs does the Part detail page show, and how are they chosen?","options":[{"id":"a","text":"A fixed five-tab layout: Info, BOM, Used In, Routing, Files — same for every part"},{"id":"b","text":"A resolver-driven multi-tab layout — tabs are computed from (procurementSource, inventoryClass) by PartDetailLayoutResolverService. Identity is always first, Activity → Files always last; intermediate tabs vary by axes","isCorrect":true},{"id":"c","text":"Whatever tabs were last visible — preference is per-user"},{"id":"d","text":"Only Identity — every other cluster opens in a separate dialog"}],"explanation":"The detail page uses PartDetailLayoutResolverService to map axes → ordered tab list. A Make + FinishedGood part might show Identity, Inventory, MRP, Cost, Pricing, Material, UoM, Quality, Routing, BOM, Sources, Alternates, Purchase History, Activity, Files. A Buy + Consumable part might show only Identity, Inventory, Cost, Pricing, Sources, Activity, Files. The 3D Viewer tab appears only when an STL file is attached."},{"id":"pt10","text":"You delete a part. What happens to the activity log for that part?","options":[{"id":"a","text":"It's deleted along with the part"},{"id":"b","text":"It's preserved — the part is soft-deleted (DeletedAt is stamped, the row stays). A 'deleted' activity row is appended","isCorrect":true},{"id":"c","text":"It's archived to a separate table"},{"id":"d","text":"It's deleted unless an admin opts in to keep it"}],"explanation":"Deletes are soft — DeletedAt + DeletedBy stamped, global query filter hides the row from normal reads, but it's still on disk. The DeletePart handler also writes a 'deleted' activity row anchored to the part, so an undelete-and-inspect flow can see exactly what happened. The same applies to every BaseEntity in the system."},{"id":"pt11","text":"Where does the New Part flow start?","options":[{"id":"a","text":"A long single-page form with every field at once"},{"id":"b","text":"A 4-question fork dialog (procurement, inventory class, traceability, inspection) that picks a workflow, then routes you into a guided multi-step form. Lightweight cases skip the workflow and use a single-page express form","isCorrect":true},{"id":"c","text":"You manually pick a workflow from a dropdown before any field"},{"id":"d","text":"There's no fork — every new part uses the same workflow"}],"explanation":"New Part starts with the fork dialog. Based on your answers, the system picks the right workflow definition (different combos use different step layouts) and routes you into it. You can pause anywhere — the partial state is saved as a draft and shown as a 'ghost' row on the parts list, resumable. Raw / Consumable cases drop directly into a one-page express form because they don't need the multi-step guidance."},{"id":"pt12","text":"Which tab on the Part detail page shows the (Vendor, Part) intersection rows — vendor's part number, lead time, MOQ, AVL approval, and tiered pricing?","options":[{"id":"a","text":"BOM"},{"id":"b","text":"Sources","isCorrect":true},{"id":"c","text":"Cost"},{"id":"d","text":"Material"}],"explanation":"The Sources tab lists VendorPart rows — one per vendor that supplies this part. It shows vendor part number, vendor MPN, per-vendor lead time, MOQ, pack size, country of origin, HTS code, AVL flag, certifications, last-quoted date, preferred flag, and the tiered pricing rows. The BOM tab shows the parts that go INTO this part; the Sources tab shows where this part comes FROM."},{"id":"pt13","text":"A Tool-class part (procurementSource = Buy, inventoryClass = Tool) is purchased and used to manufacture other parts. What special integration does it support?","options":[{"id":"a","text":"It can be linked to a tooling Asset for shot-count tracking and maintenance scheduling","isCorrect":true},{"id":"b","text":"It's automatically assigned to the Maintenance kanban board"},{"id":"c","text":"It bypasses inventory tracking entirely"},{"id":"d","text":"It can only be sold, not purchased"}],"explanation":"Tool-class parts can be linked to a tooling Asset (Asset.Type = Tooling) via the ToolingAssetId FK. The asset tracks current shot count, tool life expectancy, owner (in-house vs customer-owned), and maintenance schedule. This gives full traceability from the part record back to the physical tool that produces it."},{"id":"pt14","text":"How does the activity log handle a multi-field part update?","options":[{"id":"a","text":"One activity row per changed field"},{"id":"b","text":"One activity row per request, with a description summarizing all changed fields ('Updated 4 fields: name, description, revision, status')","isCorrect":true},{"id":"c","text":"No activity row — only created/deleted are logged"},{"id":"d","text":"Two activity rows: one for the user action, one for each field"}],"explanation":"Rollup rule: one activity row per request, regardless of how many fields the user changed. The Description summarizes the count and the field names. This keeps the activity tab readable — per-field history (with old/new values) is the History tab's job, a different concept and a different table."},{"id":"pt15","text":"You scan a barcode on the Parts page. What happens?","options":[{"id":"a","text":"A new part is created with the scanned value as the part number"},{"id":"b","text":"The scanned value is placed into the search field and the parts list reloads to find the matching part","isCorrect":true},{"id":"c","text":"The scanned part's detail panel opens immediately"},{"id":"d","text":"Nothing — barcode scanning is only supported on Inventory"}],"explanation":"On the Parts page, the global scanner context is set to 'parts'. When a barcode is scanned, the value is dropped into the search input and the list reloads with that as the search term — finds the part by its barcode-encoded part number. From there, click the row to open the detail panel."}]}"""
        });

        Log.Information("Seeded Parts training modules");
    }
}
